#!/usr/bin/env bash
set -euo pipefail
mkdir -p /etc/datamailer
cat >/etc/datamailer/environment <<ENV
DJANGO_SETTINGS_MODULE=datamailer.settings
DEBUG=False
AWS_REGION=${AWS::Region}
AWS_SES_CONFIGURATION_SET=${SESConfigurationSetName}
DEFAULT_FROM_EMAIL=${DefaultFromEmail}
PUBLIC_BASE_URL=${PublicBaseUrl}
ALLOWED_HOSTS=${WebDomainName}
CSRF_TRUSTED_ORIGINS=https://${WebDomainName}
TRANSACTIONAL_EMAIL_QUEUE_NAME=${EnvironmentName}-transactional-email
CAMPAIGN_EMAIL_QUEUE_NAME=${EnvironmentName}-campaign-email
SES_WEBHOOKS_QUEUE_NAME=${EnvironmentName}-ses-webhooks
EMAIL_EVENTS_QUEUE_NAME=${EnvironmentName}-email-events
SQS_TRANSACTIONAL_EMAIL_QUEUE_URL=${TransactionalEmailQueue}
SQS_CAMPAIGN_EMAIL_QUEUE_URL=${CampaignEmailQueue}
SQS_SES_WEBHOOKS_QUEUE_URL=${SesWebhooksQueue}
SQS_EMAIL_EVENTS_QUEUE_URL=${EmailEventsQueue}
ENV
systemctl restart datamailer || true
systemctl restart caddy || true
